#ifndef RTOS_QUEUE_H
#define RTOS_QUEUE_H
#include <Arduino.h>
#include <freertos/FreeRTOS.h>
#include <freertos/queue.h>

QueueHandle_t rtos_queue_create(UBaseType_t length, UBaseType_t itemSize);
bool rtos_queue_send(QueueHandle_t queue, const void* item, TickType_t timeout);
bool rtos_queue_receive(QueueHandle_t queue, void* item, TickType_t timeout);
UBaseType_t rtos_queue_count(QueueHandle_t queue);
bool rtos_queue_is_full(QueueHandle_t queue);

#endif

firmware_template.source:
#include "rtos_queue.h"

QueueHandle_t rtos_queue_create(UBaseType_t length, UBaseType_t itemSize) {
    QueueHandle_t q = xQueueCreate(length, itemSize);
    if (q) {
        Serial.printf("[rtos-queue] Created (len=%lu, size=%lu)\n", length, itemSize);
    } else {
        Serial.println("[rtos-queue] FAILED to create");
    }
    return q;
}

bool rtos_queue_send(QueueHandle_t queue, const void* item, TickType_t timeout) {
    if (!queue) return false;
    return xQueueSend(queue, item, timeout) == pdPASS;
}

bool rtos_queue_receive(QueueHandle_t queue, void* item, TickType_t timeout) {
    if (!queue) return false;
    return xQueueReceive(queue, item, timeout) == pdPASS;
}

UBaseType_t rtos_queue_count(QueueHandle_t queue) {
    return queue ? uxQueueMessagesWaiting(queue) : 0;
}

bool rtos_queue_is_full(QueueHandle_t queue) {
    return queue ? (uxQueueSpacesAvailable(queue) == 0) : true;
}
